brandingConfig.customCss:
@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700;800&family=Space+Grotesk:wght@400;500;700&family=Bungee:wght@400&display=swap');

:root {
  color-scheme: light;

  --text-primary: #240046;
  --text-secondary: #5a189a;
  --text-muted: #7b5ea7;
  --bg-page: #fff7fd;
  --bg-card: rgba(255, 255, 255, 0.8);
  --border-subtle: rgba(255, 0, 170, 0.14);

  --tenant-font: "Outfit", "Space Grotesk", sans-serif;
  --tenant-primary-color: #ff006e;
  --tenant-primary-soft-color: rgba(255, 0, 110, 0.12);
  --tenant-secondary-color: #00f5d4;
  --tenant-secondary-soft-color: rgba(0, 245, 212, 0.14);

  --tenant-side-nav-bg: linear-gradient(180deg, rgba(33, 0, 61, 0.94) 0%, rgba(90, 24, 154, 0.92) 52%, rgba(255, 0, 110, 0.84) 100%);
  --tenant-side-nav-border: rgba(255, 255, 255, 0.12);
  --tenant-side-nav-title: #ffffff;
  --tenant-side-nav-text: #f8ecff;
  --tenant-side-nav-muted: rgba(255, 255, 255, 0.72);
  --tenant-side-nav-item-bg: rgba(255, 255, 255, 0.08);
  --tenant-side-nav-item-text: #ffffff;
  --tenant-side-nav-item-description: rgba(255, 255, 255, 0.78);
  --tenant-side-nav-item-hover-bg: rgba(255, 255, 255, 0.14);
  --tenant-side-nav-item-hover-text: #ffffff);
  --tenant-side-nav-item-active-bg: linear-gradient(135deg, #ff006e 0%, #8338ec 56%, #00f5d4 100%);
  --tenant-side-nav-item-active-text: #ffffff;
}

body {
  background:
    radial-gradient(circle at top left, rgba(255, 0, 110, 0.14), transparent 22rem),
    radial-gradient(circle at top right, rgba(131, 56, 236, 0.12), transparent 24rem),
    linear-gradient(135deg, #fff8fd 0%, #fff2fb 40%, #f5fcff 100%);
  font-family: var(--tenant-font);
  color: var(--text-primary);
}

h1,
h2,
h3,
h4,
.tenant-portal-header__title,
.member-panel__headline,
.member-panel__title {
  font-family: "Bungee", "Outfit", sans-serif;
  letter-spacing: 0.01em;
}

.portal-card,
.member-panel,
.member-support-tile,
.tenant-progress-meter,
.tenant-portal-header__shell {
  background: linear-gradient(180deg, rgba(255,255,255,0.88), rgba(255,255,255,0.74)) !important;
  border-color: rgba(255, 0, 170, 0.14) !important;
  border-radius: 24px !important;
  box-shadow:
    0 18px 36px rgba(58, 12, 163, 0.1),
    0 1px 0 rgba(255,255,255,0.72) inset !important;
  backdrop-filter: blur(16px);
}

.tenant-portal-header__band {
  background: linear-gradient(180deg, rgba(255, 0, 110, 0.08), rgba(131, 56, 236, 0.08)) !important;
}

.tenant-portal-header__logo-frame {
  background: rgba(255,255,255,0.92) !important;
  border-color: rgba(255, 0, 170, 0.12) !important;
  border-radius: 28px !important;
}

.tenant-portal-header__title,
.tenant-portal-header__meta,
.tenant-portal-header__welcome,
.tenant-portal-header__support,
.member-panel__headline,
.member-panel__subcopy,
.member-panel__title,
.member-snapshot-row__label,
.member-snapshot-row__value,
.member-action-card__value,
.member-support-tile__title,
.member-support-tile__detail,
.tenant-progress-meter__title,
.tenant-progress-meter__helper,
.tenant-progress-meter__values {
  color: var(--text-primary);
}

.tenant-portal-header__welcome,
.tenant-portal-header__meta,
.tenant-portal-header__support,
.member-panel__subcopy,
.member-action-card__detail,
.member-support-tile__detail,
.tenant-progress-meter__helper,
.tenant-progress-meter__values {
  color: var(--text-secondary) !important;
}

.member-panel__eyebrow,
.tenant-progress-meter__percent,
.member-panel__link {
  color: var(--tenant-primary-color) !important;
}

.member-panel__status {
  background: linear-gradient(135deg, rgba(16, 185, 129, 0.16), rgba(0, 245, 212, 0.14)) !important;
  color: #047857 !important;
}

.member-action-card {
  background: rgba(255, 248, 254, 0.9) !important;
  border-color: rgba(255, 0, 170, 0.14) !important;
  border-radius: 20px !important;
}

.member-action-card__label,
.member-activity-item__timestamp,
.member-support-tile__detail,
.member-snapshot-row__label {
  color: var(--text-muted) !important;
}

.member-action-card:hover,
.member-support-tile:hover,
.member-activity-item:hover {
  border-color: rgba(255, 0, 110, 0.34) !important;
  box-shadow: 0 10px 24px rgba(255, 0, 110, 0.1);
}

.tenant-progress-meter__track {
  background: rgba(131, 56, 236, 0.1) !important;
}

.tenant-progress-meter__fill {
  background: linear-gradient(90deg, #ff006e 0%, #8338ec 56%, #00f5d4 100%) !important;
}

.member-activity-item {
  background: rgba(255,255,255,0.72) !important;
  border-color: rgba(255, 0, 170, 0.12) !important;
  border-radius: 18px !important;
}

.tenant-side-nav {
  background: var(--tenant-side-nav-bg) !important;
  border-color: var(--tenant-side-nav-border) !important;
  box-shadow:
    0 24px 48px rgba(58, 12, 163, 0.22),
    inset 0 1px 0 rgba(255, 255, 255, 0.14) !important;
  backdrop-filter: blur(18px);
}

.tenant-side-nav__header {
  border-bottom-color: rgba(255,255,255,0.14) !important;
}

.tenant-side-nav__title {
  color: var(--tenant-side-nav-title) !important;
}

.tenant-side-nav__description {
  color: var(--tenant-side-nav-text) !important;
}

.tenant-side-nav__section-title {
  color: var(--tenant-side-nav-muted) !important;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.tenant-side-nav__item {
  background: var(--tenant-side-nav-item-bg) !important;
  color: var(--tenant-side-nav-item-text) !important;
  border-color: rgba(255,255,255,0.08) !important;
  border-radius: 18px !important;
}

.tenant-side-nav__item-label {
  color: inherit !important;
  font-family: "Space Grotesk", "Outfit", sans-serif !important;
  font-weight: 700 !important;
}

.tenant-side-nav__item-description {
  color: var(--tenant-side-nav-item-description) !important;
}

.tenant-side-nav__item:hover {
  background: var(--tenant-side-nav-item-hover-bg) !important;
  color: var(--tenant-side-nav-item-hover-text) !important;
  border-color: rgba(0, 245, 212, 0.32) !important;
}

.tenant-side-nav__item:hover .tenant-side-nav__item-description {
  color: #ffffff !important;
}

.tenant-side-nav__item--active {
  background: var(--tenant-side-nav-item-active-bg) !important;
  color: var(--tenant-side-nav-item-active-text) !important;
  border-color: rgba(255,255,255,0.2) !important;
  box-shadow: 0 10px 24px rgba(255, 0, 110, 0.24) !important;
}

.tenant-side-nav__item--active .tenant-side-nav__item-label,
.tenant-side-nav__item--active .tenant-side-nav__item-description {
  color: #ffffff !important;
}

button[class*="bg-[var(--tenant-primary-color)]"],
a[class*="bg-[var(--tenant-primary-color)]"] {
  background: linear-gradient(135deg, #ff006e 0%, #ff4ecd 34%, #8338ec 68%, #00f5d4 100%) !important;
  color: #ffffff !important;
  border: 0 !important;
  box-shadow: 0 14px 30px rgba(255, 0, 110, 0.24);
}

button[class*="border-[var(--tenant-primary-color)]"],
a[class*="border-[var(--tenant-primary-color)]"] {
  border-color: #8338ec !important;
  color: #5a189a !important;
}
